const seen = new Set();
const items = [];
for (const item of $input.all()) {
  for (const v of (item.json.objects || [])) {
    if (!seen.has(v.id)) {
      seen.add(v.id);
      items.push({ json: v });
    }
  }
}
return items;

const SKR04_MAP = {
  '6300':'2','6310':'52','6325':'53','6335':'69','6400':'91',
  '6520':'8','6530':'5','6540':'6','6570':'12','6600':'97',
  '6640':'44','6643':'43','6670':'61','6673':'62','6680':'66',
  '6800':'75','6805':'88','6810':'89','6815':'72','6820':'78',
  '6825':'22','6827':'23','6830':'2816','6837':'2819',
  '6840':'51','6855':'74','7135':'69','7310':'73','7320':'13'
};

const raw = $input.item.json;
const prev = $('Claude vorbereiten').item.json;

let text = raw.content[0].text.trim()
  .replace(/^```(?:json)?\s*/m,'').replace(/\s*```$/m,'');
const m = text.match(/\{[\s\S]*\}/);
if (!m) throw new Error('Kein JSON in Claude-Antwort');
const result = JSON.parse(m[0]);

const parseDate = s => {
  if (!s || !/^\d{2}\.\d{2}\.\d{4}$/.test(s)) return null;
  const [d,mo,y] = s.split('.');
  return new Date(`${y}-${mo}-${d}`);
};
const rdatum = parseDate(result.rechnungsdatum);
const beforeCutoff = !!(rdatum && rdatum < new Date('2026-01-01'));

const warnings = [];
if (!result.lieferant)      warnings.push('Lieferant fehlt');
if (!result.rechnungsdatum) warnings.push('Datum fehlt');
if (!result.bruttobetrag)   warnings.push('Brutto fehlt');
if (Number(result.bruttobetrag) === 0) warnings.push('Brutto ist 0');
if (beforeCutoff)           warnings.push('Vor Stichtag 01.01.2026 — nicht buchen');
if (result.waehrung && result.waehrung !== 'EUR') warnings.push('Fremdwährung: ' + result.waehrung);

const accountingTypeId = SKR04_MAP[String(result.sollkonto)] || null;
if (result.sollkonto && !accountingTypeId) warnings.push('Kein AccountingType für Konto ' + result.sollkonto);

return [{ json: { voucher_id: prev.voucher_id, result, warnings, beforeCutoff, accountingTypeId, usage: raw.usage } }];

const sevdeskToken = $('Zugangsdaten').first().json.sevdeskToken;
const { voucher_id, result, accountingTypeId, warnings } = $input.item.json;
const BASE = 'https://my.sevdesk.de/api/v1';
const ah = { 'Authorization': sevdeskToken };
const jh = { 'Authorization': sevdeskToken, 'Content-Type': 'application/json' };

const req = async (method, path, body) => {
  const opts = { method, url: BASE + path, headers: body ? jh : ah };
  if (body) opts.body = JSON.stringify(body);
  const r = await this.helpers.httpRequest(opts);
  return typeof r === 'string' ? JSON.parse(r) : r;
};

// 1. Kontakt suchen
let contactId = null;
try {
  const s = await req('GET', '/Contact?name=' + encodeURIComponent(result.lieferant) + '&limit=5');
  if (s.objects?.length) contactId = s.objects[0].id;
} catch(e) {}

// 2. Kontakt anlegen
if (!contactId && result.lieferant) {
  try {
    const payload = { name: result.lieferant, category: { id: '2', objectName: 'Category' } };
    if (result.lieferant_ust_id) payload.vatNumber = result.lieferant_ust_id;
    const c = await req('POST', '/Contact', payload);
    contactId = c.objects?.id || null;
    if (contactId && (result.lieferant_strasse || result.lieferant_ort)) {
      await req('POST', '/ContactAddress', {
        contact: { id: contactId, objectName: 'Contact' },
        street: result.lieferant_strasse || '',
        zip:    result.lieferant_plz    || '',
        city:   result.lieferant_ort    || '',
        country:  { id: '1',  objectName: 'StaticCountry' },
        category: { id: '48', objectName: 'Category' }
      });
    }
  } catch(e) {}
}

// 3. Kontakt mit Voucher verknüpfen
if (contactId) {
  try { await req('PUT', '/Voucher/' + voucher_id, { supplier: { id: contactId, objectName: 'Contact' }, supplierName: null }); }
  catch(e) {}
}

// 4. AccountingType auf alle VoucherPos setzen
if (accountingTypeId) {
  try {
    const pos = await req('GET', '/VoucherPos?voucher%5Bid%5D=' + voucher_id + '&voucher%5BobjectName%5D=Voucher');
    for (const p of (pos.objects || [])) {
      await req('PUT', '/VoucherPos/' + p.id, { accountingType: { id: accountingTypeId, objectName: 'AccountingType' } });
    }
  } catch(e) {}
}

return [{ json: {
  voucher_id,
  lieferant:          result.lieferant,
  datum:              result.rechnungsdatum,
  brutto:             result.bruttobetrag,
  sollkonto:          result.sollkonto,
  accounting_type_id: accountingTypeId,
  kontakt_id:         contactId,
  status:             warnings.length > 0 ? 'klaeren' : 'ok',
  warnings
} }];
